local LxBaseMgr = require("LApp.Manager.LxBaseMgr")
---@class LGameI18n : LxBaseMgr
local LGameI18n = LxClass("LGameI18n", LxBaseMgr)
------------------------------------------------------------------
function LGameI18n:Initialize()
    self._lng = "zhcn"
    self._i18nDatas = {}
end

function LGameI18n:Dispose()
    LxBaseMgr.Dispose(self)
end

function LGameI18n:LoadLng()
    local lng = self._lng
    local data = self._i18nDatas[lng]
    if not data then
        data = {
            texts = {},
            caches = {},
            tableFiles = {},
            tableReqs = {},
        }
        self._i18nDatas[lng] = data
    end

    self._texts  = data.texts
    self._caches = data.caches
    self._tableFiles = data.tableFiles
    self._tableReqs = data.tableReqs
end

function LGameI18n:SetLng(lng)
    if LOG_INFO_ENABLED then
        LogWarn("LGameI18n:SetLng:" ..lng )
    end
    self._lng = lng
end

function LGameI18n:I18nLng(textId)
    if not textId then return nil end
    return self:_InternalI18nFromTable(textId)
end

function LGameI18n:I18nText(textId)
    if not textId then return nil end
    local cfg = GameTable.TextCRef[textId]
    if cfg then
        return self:_InternalI18nFromTable(cfg.text)
    end
    return nil
end

function LGameI18n:I18nError(code)
    if not code then return end
    local cfg = GameTable.TextSRef[code]
    if cfg then
        return self:_InternalI18nFromTable(cfg.text)
    end
    return nil
end

local IosVerifyRef = nil
function LGameI18n:VerifyIos(tableName)
    if not IosVerifyRef then
        IosVerifyRef = LxRequireWithoutReload(LGameLanguage.CONF_DEFAULT_PATH .. "IosApproveRef")
    end
    local ref = IosVerifyRef[tableName]
    if ref and ref.ios > 0 then
        return true
    end
    return false
end

function LGameI18n:_InternalFindTable(tableName)
    if self._tableReqs[tableName] then
        return self._tableFiles[tableName]
    else

        local fmtStr = "i18n.%s.%s"
        if PRODUCT_G_VER and PRODUCT_G_VER ~= 0 then
            if self:VerifyIos(tableName) then
                fmtStr = "i18n_ios.%s.%s"
            end
        end
        local tablePath = string.format(fmtStr,tostring(self._lng), tableName)
        local tableFile = LxRequireWithoutReload(tablePath)
        if tableFile then self._tableFiles[tableName] = tableFile end
        self._tableReqs[tableName] = tablePath
        return tableFile
    end
end

function LGameI18n:HotReload()
    local _texts = self._texts
    for k,v in pairs(_texts) do
        _texts[k] = nil
    end
    local _caches = self._caches
    for k,v in pairs(_caches) do
        _caches[k] = nil
    end
    local _tableReqs = self._tableReqs
    local _tableFiles = self._tableFiles
    local loaded = package.loaded
    local preload = package.preload
    for k,path in pairs(_tableReqs) do
        _tableReqs[k] = nil
        if _tableFiles[k] then
            _tableFiles[k] = nil
            preload[path] = nil
            loaded[path] = nil
        end
    end
end

function LGameI18n:_InternalI18nFromTable(idForTable)
    if string.isempty(idForTable) then return nil end

    if self._caches[idForTable] then
        return self._texts[idForTable]
    end

    local str = nil
    local idx = string.find(idForTable, "_")
    if idx then
        local tableFile = self:_InternalFindTable(string.sub(idForTable, 1, idx - 1))
        if tableFile then str = tableFile[idForTable] end
    end

    self._caches[idForTable] = true
    self._texts[idForTable] = str
    return str
end

return LGameI18n